import java.util.Scanner;

public class SecureBuffer {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter a string: ");
        String userInput = scanner.nextLine();

        // Define a safe buffer size
        int bufferSize = Math.min(userInput.length(), 10);

        char[] buffer = new char[bufferSize]; // Buffer with dynamic size based on user input

        // Copy user input into buffer with proper boundary checking
        for (int i = 0; i < bufferSize; i++) {
            buffer[i] = userInput.charAt(i);
        }

        System.out.println("Buffer contents: " + new String(buffer));
    }
}

### Explanation:
취약유형: Buffer Overflow
